            edge_data = graph_copy['ju1.a4.dom'][child]
            if 'RK_CONTAINS' in edge_data.get('type', []):
                direct_children.append(child)
    results = []
    for child_id in direct_children:
        total_cap = 0
        queue = [child_id]
        visited = set()
        while queue:
            node_id = queue.pop(0)
            if node_id in visited:
                continue
