                if 'RK_CONTAINS' in edge_data.get('type', []):
                    queue.append(succ)
        results.append((child_id, total_cap))
    results.sort(key=lambda x: x[1], reverse=True)
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
